import "./navbar.css";
import MenuVertical from './menuvertical/menu-vertical.js'
import { Link } from "react-router-dom";

function Navbar() {

    return (

        <nav className="container-navbar">
            <ul className="nav-list">
                <Link href="index.html"><img src="LOGO-B.png" alt='Logo' /></Link>
                <li className="nav-item"><Link href="/">INICIO</Link></li>

                <li className="nav-item-menuv">
                    <Link href="/Productos">PRODUCTOS</Link>
                    <MenuVertical />
                </li>
                <li className="nav-item"><Link href="Contacto">CONTACTO</Link></li>
                <li className="nav-item"><Link href="Contacto"><img src="carrito.svg"/></Link></li>
            </ul>
        </nav>

    );
};

export default Navbar;
